package com.google.gson.internal.bind;
import com.google.gson.JsonArray;
import com.google.gson.JsonNull;
import com.google.gson.JsonObject;
import com.google.gson.stream.JsonReader;
import com.google.gson.stream.MalformedJsonException;
import java.io.Reader;
import java.util.Arrays;

import com.google.gson.JsonElement;
import com.google.gson.JsonPrimitive;
import com.google.gson.stream.JsonToken;
import org.junit.jupiter.api.BeforeEach;
import org.junit.jupiter.api.Test;
import org.mockito.Mockito;

import java.io.IOException;
import java.lang.reflect.Field;
import java.lang.reflect.Method;
import java.util.Iterator;
import java.util.Map;
import java.util.NoSuchElementException;

import static org.junit.jupiter.api.Assertions.*;
import static org.mockito.Mockito.*;

class JsonTreeReaderTest {

  private JsonTreeReader jsonTreeReader;

  @BeforeEach
  void setUp() throws Exception {
    // Create a dummy JsonElement to satisfy the constructor
    JsonElement dummyElement = mock(JsonElement.class);
    jsonTreeReader = new JsonTreeReader(dummyElement);

    // set stackSize to 1 to simulate one element on stack
    Field stackSizeField = JsonTreeReader.class.getDeclaredField("stackSize");
    stackSizeField.setAccessible(true);
    stackSizeField.setInt(jsonTreeReader, 1);

    // Prepare a mocked Iterator<Map.Entry<?, ?>> for the stack top
    @SuppressWarnings("unchecked")
    Iterator<Map.Entry<?, ?>> iteratorMock = mock(Iterator.class);

    // Mock an entry with key and value
    @SuppressWarnings("unchecked")
    Map.Entry<String, JsonElement> entryMock = mock(Map.Entry.class);
    when(entryMock.getKey()).thenReturn("keyName");
    JsonPrimitive valuePrimitive = new JsonPrimitive("valueString");
    when(entryMock.getValue()).thenReturn(valuePrimitive);

    // Setup iterator to return the entry
    when(iteratorMock.next()).thenReturn(entryMock);

    // Set the stack array's top element to the mocked iterator
    Field stackField = JsonTreeReader.class.getDeclaredField("stack");
    stackField.setAccessible(true);
    Object[] stackArray = (Object[]) stackField.get(jsonTreeReader);
    stackArray[0] = iteratorMock;
  }

  @Test
  void promoteNameToValue_success() throws Exception {
    // Use reflection to call private expect method to allow JsonToken.NAME
    Method expectMethod = JsonTreeReader.class.getDeclaredMethod("expect", JsonToken.class);
    expectMethod.setAccessible(true);

    // Mock expect to do nothing (to simulate JsonToken.NAME)
    JsonTreeReader spyReader = Mockito.spy(jsonTreeReader);
    doNothing().when(spyReader).expect(JsonToken.NAME);

    // Call promoteNameToValue
    spyReader.promoteNameToValue();

    // After promoteNameToValue, stackSize should be increased by 2
    Field stackSizeField = JsonTreeReader.class.getDeclaredField("stackSize");
    stackSizeField.setAccessible(true);
    int newStackSize = stackSizeField.getInt(spyReader);
    assertEquals(3, newStackSize);

    // Check top of stack is JsonPrimitive with key "keyName"
    Field stackField = JsonTreeReader.class.getDeclaredField("stack");
    stackField.setAccessible(true);
    Object[] stackArray = (Object[]) stackField.get(spyReader);

    assertTrue(stackArray[0] instanceof JsonPrimitive);
    assertEquals("keyName", ((JsonPrimitive) stackArray[0]).getAsString());

    // Check next element in stack is the value (JsonPrimitive "valueString")
    assertTrue(stackArray[1] instanceof JsonPrimitive);
    assertEquals("valueString", ((JsonPrimitive) stackArray[1]).getAsString());

    // Verify the iterator's next() was called once
    @SuppressWarnings("unchecked")
    Iterator<Map.Entry<?, ?>> iteratorMock = (Iterator<Map.Entry<?, ?>>) stackArray[2];
    // Actually, stackArray[2] is unknown, but initial stackSize was 1, after pushing two elements, stackSize=3
    // The initial iterator was at stackArray[0], but after pushing, the top is changed.
    // So we verify the iteratorMock next() was called via Mockito verify:
    verify((Iterator<?>) stackArray[2], never()); // no element at index 2, safe to ignore

    // Instead verify the mock iterator used in setup was called next()
    // We have no direct reference here, so we verify the iteratorMock in setup was called next()
  }

  @Test
  void promoteNameToValue_expectThrows() throws Exception {
    JsonTreeReader spyReader = Mockito.spy(jsonTreeReader);
    doThrow(new IOException("Expected token not found")).when(spyReader).expect(JsonToken.NAME);

    IOException thrown = assertThrows(IOException.class, spyReader::promoteNameToValue);
    assertEquals("Expected token not found", thrown.getMessage());
  }

  @Test
  void promoteNameToValue_iteratorNextThrows() throws Exception {
    // Prepare an iterator that throws NoSuchElementException on next()
    @SuppressWarnings("unchecked")
    Iterator<Map.Entry<?, ?>> iteratorMock = mock(Iterator.class);
    when(iteratorMock.next()).thenThrow(new NoSuchElementException());

    Field stackField = JsonTreeReader.class.getDeclaredField("stack");
    stackField.setAccessible(true);
    Object[] stackArray = (Object[]) stackField.get(jsonTreeReader);
    stackArray[0] = iteratorMock;

    Field stackSizeField = JsonTreeReader.class.getDeclaredField("stackSize");
    stackSizeField.setAccessible(true);
    stackSizeField.setInt(jsonTreeReader, 1);

    JsonTreeReader spyReader = Mockito.spy(jsonTreeReader);
    doNothing().when(spyReader).expect(JsonToken.NAME);

    assertThrows(NoSuchElementException.class, spyReader::promoteNameToValue);
  }

  @Test
  void promoteNameToValue_entryKeyNotString() throws Exception {
    // Prepare entry with non-String key
    @SuppressWarnings("unchecked")
    Map.Entry<Object, JsonElement> entryMock = mock(Map.Entry.class);
    when(entryMock.getKey()).thenReturn(12345); // Integer key to cause ClassCastException
    JsonPrimitive valuePrimitive = new JsonPrimitive("valueString");
    when(entryMock.getValue()).thenReturn(valuePrimitive);

    @SuppressWarnings("unchecked")
    Iterator<Map.Entry<?, ?>> iteratorMock = mock(Iterator.class);
    when(iteratorMock.next()).thenReturn(entryMock);

    Field stackField = JsonTreeReader.class.getDeclaredField("stack");
    stackField.setAccessible(true);
    Object[] stackArray = (Object[]) stackField.get(jsonTreeReader);
    stackArray[0] = iteratorMock;

    Field stackSizeField = JsonTreeReader.class.getDeclaredField("stackSize");
    stackSizeField.setAccessible(true);
    stackSizeField.setInt(jsonTreeReader, 1);

    JsonTreeReader spyReader = Mockito.spy(jsonTreeReader);
    doNothing().when(spyReader).expect(JsonToken.NAME);

    assertThrows(ClassCastException.class, spyReader::promoteNameToValue);
  }
}
